using namespace std;

typedef struct {
  float weight;
  long assign;
  float cost;
} Point_Struct;

typedef struct {
  float weight;
  float * coord;
  long assign;
  float cost;
} Point;

typedef struct {
  long num;
  int dim;
  Point *p;
} Points;

struct pkmedian_arg_t
{
  Points* points;
  long kmin;
  long kmax;
  long* kfinal;
  int pid;
  pthread_barrier_t* barrier;
};

static char *switch_membership;
static bool *is_center;
static int  *center_table;
static int nproc;

static double serial;
static double cpu_gpu_memcpy;
static double memcpy_back;
static double gpu_malloc;
static double kernel;
static double gpu_free;
static int cnt_speedy;

double gettime() {
  struct timeval t;
  gettimeofday(&t,NULL);
  return t.tv_sec+t.tv_usec*1e-6;
}

int isIdentical(float *i, float *j, int D){
  int a = 0;
  int equal = 1;
  while (equal && a < D) {
    if (i[a] != j[a]) equal = 0;
    else a++;
  }
  if (equal) return 1;
  else return 0;
}

static int floatcomp(const void *i, const void *j)
{
  float a, b;
  a = *(float *)(i);
  b = *(float *)(j);
  if (a > b) return (1);
  if (a < b) return (-1);
  return(0);
}

void shuffle(Points *points)
{
  long i, j;
  Point temp;
  for (i=0;i<points->num-1;i++) {
    j=(lrand48()%(points->num - i)) + i;
    temp = points->p[i];
    points->p[i] = points->p[j];
    points->p[j] = temp;
  }
}

void intshuffle(int *intarray, int length)
{
  long i, j;
  int temp;
  for (i=0;i<length;i++) {
    j=(lrand48()%(length - i))+i;
    temp = intarray[i];
    intarray[i]=intarray[j];
    intarray[j]=temp;
  }
}

float dist(Point p1, Point p2, int dim)
{
  int i;
  float result=0.0;
  for (i=0;i<dim;i++)
    result += (p1.coord[i] - p2.coord[i])*(p1.coord[i] - p2.coord[i]);
  return(result);
}

float pgain(long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center, int *center_table, char *switch_membership,
							double *serial, double *cpu_gpu_memcpy, double *memcpy_back, double *gpu_malloc, double *kernel){
	float gl_cost = 0;
	int K	= *numcenters ;
	int num    =   points->num;
	int dim     =   points->dim;
	kmax++;

	int count = 0;
	for( int i=0; i<num; i++){
		if( is_center[i] )
			center_table[i] = count++;
	}

	static int c = 0;

	static float *work_mem_h = NULL;
	static float *coord_h = NULL;
	static float *gl_lower = NULL;
	static Point_Struct *p_h = NULL;

	if( c == 0 ) {
		coord_h = (float*) malloc( num * dim * sizeof(float));
		gl_lower = (float*) malloc( kmax * sizeof(float) );
		work_mem_h = (float*) malloc(kmax*num*sizeof(float));
		p_h = (Point_Struct*)malloc(num*sizeof(Point_Struct));

		for(int i=0; i<dim; i++){
			for(int j=0; j<num; j++)
				coord_h[ (num*i)+j ] = points->p[j].coord[i];
		}
	}

	for(int i=0; i<num; i++){
		p_h[i].weight = ((points->p)[i]).weight;
		p_h[i].assign = ((points->p)[i]).assign;
		p_h[i].cost = ((points->p)[i]).cost;
	}

	// memset switch_membership and work_mem_h to zero
	memset(switch_membership, 0, num*sizeof(char));
	memset(work_mem_h, 0, (K+1)*num*sizeof(float));

	// Shared coordinate for point x
	float *coord_s = (float*) malloc(dim * sizeof(float));
	for(int i=0; i<dim; i++){
		coord_s[i] = coord_h[i*num + x];
	}

	// Parallel loop over points
#pragma omp parallel for schedule(static)
	for(int thread_id=0; thread_id<num; thread_id++){
		float x_cost = 0.0f;
		for(int i=0; i<dim; i++)
			x_cost += (coord_h[(i*num)+thread_id]-coord_s[i]) * (coord_h[(i*num)+thread_id]-coord_s[i]);
		x_cost = x_cost * p_h[thread_id].weight;

		float current_cost = p_h[thread_id].cost;

		int base = thread_id*(K+1);

		if ( x_cost < current_cost ){
			switch_membership[thread_id] = '1';
			int addr_1 = base + K;
#pragma omp atomic write
			work_mem_h[addr_1] = x_cost - current_cost;
		}
		else {
			int assign = p_h[thread_id].assign;
			int addr_2 = base + center_table[assign];
#pragma omp atomic
			work_mem_h[addr_2] += current_cost - x_cost;
		}
	}

	free(coord_s);

	int numclose = 0;
	gl_cost = z;

	for(int i=0; i < num; i++){
		if( is_center[i] ) {
			float low = z;

			for( int j = 0; j < num; j++ )
				low += work_mem_h[ j*(K+1) + center_table[i] ];

			gl_lower[center_table[i]] = low;

			if ( low > 0 ) {
				numclose++;
				work_mem_h[i*(K+1)+K] -= low;
			}
		}
		gl_cost += work_mem_h[i*(K+1)+K];
	}

	if ( gl_cost < 0 ) {
		for(int i=0; i<num; i++){

			bool close_center = gl_lower[center_table[points->p[i].assign]] > 0 ;
			if ( (switch_membership[i]=='1') || close_center ) {
				points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
				points->p[i].assign = x;
			}
		}

		for(int i=0; i<num; i++){
			if( is_center[i] && gl_lower[center_table[i]] > 0 )
				is_center[i] = false;
		}

		is_center[x] = true;
		*numcenters = *numcenters +1 - numclose;
	}
	else
		gl_cost = 0;

	c++;

	return -gl_cost;
}

float pspeedy(Points *points, float z, long *kcenter, int pid, pthread_barrier_t* barrier)
{
	cnt_speedy++;

	long bsize = points->num/nproc;
	long k1 = bsize * pid;
	long k2 = k1 + bsize;
	if( pid == nproc-1 ) k2 = points->num;

	static float totalcost;

	static bool open = false;
	static float* costs;
	static int i;

	for( int k = k1; k < k2; k++ )    {
		float distance = dist(points->p[k],points->p[0],points->dim);
		points->p[k].cost = distance * points->p[k].weight;
		points->p[k].assign=0;
	}

	if( pid==0 )   {
		*kcenter = 1;
		costs = (float*)malloc(sizeof(float)*nproc);
	}

	if( pid != 0 ) {
		while(1) {
			if( i >= points->num ) break;
			for( int k = k1; k < k2; k++ )
			{
				float distance = dist(points->p[i],points->p[k],points->dim);
				if( distance*points->p[k].weight < points->p[k].cost )
				{
					points->p[k].cost = distance * points->p[k].weight;
					points->p[k].assign=i;
				}
			}
		}
	}
	else  {
		for(i = 1; i < points->num; i++ )  {
			bool to_open = ((float)lrand48()/(float)INT_MAX)<(points->p[i].cost/z);
			if( to_open )  {
				(*kcenter)++;
				open = true;
				for( int k = k1; k < k2; k++ )  {
					float distance = dist(points->p[i],points->p[k],points->dim);
					if( distance*points->p[k].weight < points->p[k].cost )  {
						points->p[k].cost = distance * points->p[k].weight;
						points->p[k].assign=i;
					}
				}
				open = false;
			}
		}
		open = true;
	}
	float mytotal = 0;
	for( int k = k1; k < k2; k++ )  {
		mytotal += points->p[k].cost;
	}
	costs[pid] = mytotal;

	if( pid == 0 )
	{
		totalcost=z*(*kcenter);
		for( int i = 0; i < nproc; i++ )
		{
			totalcost += costs[i];
		}
		free(costs);
	}

	open = false;
	return(totalcost);
}

float pFL(Points *points, int *feasible, int numfeasible,
	  float z, long *k, int kmax, float cost, long iter, float e,
	  int pid, pthread_barrier_t* barrier)
{
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
  long i;
  long x;
  float change;
  long numberOfPoints;

  change = cost;

  while (change/cost > 1.0*e) {
    change = 0.0;
    numberOfPoints = points->num;

    if( pid == 0 ) {
      intshuffle(feasible, numfeasible);
    }
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
    for (i=0;i<iter;i++) {
	    x = i%numfeasible;

	    change += pgain(feasible[x], points, z, k, kmax, is_center, center_table, switch_membership,
												&serial, &cpu_gpu_memcpy, &memcpy_back, &gpu_malloc, &kernel);
    }
    cost -= change;
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
  }
  return(cost);
}

int selectfeasible_fast(Points *points, int **feasible, int kmin, int pid, pthread_barrier_t* barrier)
{
  int numfeasible = points->num;
  if (numfeasible > (3*kmin*log((float)kmin)))
    numfeasible = (int)(3*kmin*log((float)kmin));
  *feasible = (int *)malloc(numfeasible*sizeof(int));

  float* accumweight;
  float totalweight;

  long k1 = 0;
  long k2 = numfeasible;

  float w;
  int l,r,k;

  if (numfeasible == points->num) {
    for (int i=k1;i<k2;i++)
      (*feasible)[i] = i;
    return numfeasible;
  }

  accumweight= (float*)malloc(sizeof(float)*points->num);
  accumweight[0] = points->p[0].weight;
  totalweight=0;
  for( int i = 1; i < points->num; i++ ) {
    accumweight[i] = accumweight[i-1] + points->p[i].weight;
  }
  totalweight=accumweight[points->num-1];

  for(int i=k1; i<k2; i++ ) {
    w = (lrand48()/(float)INT_MAX)*totalweight;

    l=0;
    r=points->num-1;
    if( accumweight[0] > w )  {
      (*feasible)[i]=0;
      continue;
    }
    while( l+1 < r ) {
      k = (l+r)/2;
      if( accumweight[k] > w ) {
	r = k;
      }
      else {
	l=k;
      }
    }
    (*feasible)[i]=r;
  }
  free(accumweight);
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long* kfinal,
	       int pid, pthread_barrier_t* barrier )
{
  int i;
  float cost;
  float lastcost;
  float hiz, loz, z;

  static long k;
  static int *feasible;
  static int numfeasible;
  static float* hizs;

  if( pid==0 ) hizs = (float*)calloc(nproc,sizeof(float));
  hiz = loz = 0.0;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( pid == nproc-1 ) k2 = points->num;

  float myhiz = 0;
  for (long kk=k1;kk < k2; kk++ ) {
    myhiz += dist(points->p[kk], points->p[0],
		      ptDimension)*points->p[kk].weight;
  }
  hizs[pid] = myhiz;

  for( int i = 0; i < nproc; i++ )   {
    hiz += hizs[i];
  }

  loz=0.0; z = (hiz+loz)/2.0;

  if (points->num <= kmax) {

    for (long kk=k1;kk<k2;kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    if( pid== 0 ) {
      free(hizs);
      *kfinal = k;
    }
    return cost;
  }

  if( pid == 0 ) shuffle(points);
  cost = pspeedy(points, z, &k, pid, barrier);
  i=0;

  while ((k < kmin)&&(i<1)) {
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

  while (k < kmin) {
    if (i >= 1) {hiz=z; z=(hiz+loz)/2.0; i=0;}
    if( pid == 0 ) shuffle(points);
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

  if( pid == 0 )
  {
    numfeasible = selectfeasible_fast(points,&feasible,kmin,pid,barrier);
    for( int i = 0; i< points->num; i++ ) {
      is_center[points->p[i].assign]= true;
    }
  }

  while(1) {
    lastcost = cost;
    cost = pFL(points, feasible, numfeasible,
	       z, &k, kmax, cost, (long)(3*kmax*log((float)kmax)), 0.1, pid, barrier);

    if (((k <= (1.1)*kmax)&&(k >= (0.9)*kmin))||
	((k <= kmax+2)&&(k >= kmin-2))) {
      cost = pFL(points, feasible, numfeasible,
		 z, &k, kmax, cost, (long)(3*kmax*log((float)kmax)), 0.001, pid, barrier);
    }

    if (k > kmax) {
      loz = z; z = (hiz+loz)/2.0;
      cost += (z-loz)*k;
    }
    if (k < kmin) {
      hiz = z; z = (hiz+loz)/2.0;
      cost += (z-hiz)*k;
    }

    if (((k <= kmax)&&(k >= kmin))||((loz >= (0.999)*hiz)) )
      {
	break;
      }
  }

  if( pid==0 ) {
    free(feasible);
    free(hizs);
    *kfinal = k;
  }

  return cost;
}

int contcenters(Points *points)
{
  long i, ii;
  float relweight;

  for (i=0;i<points->num;i++) {

    if (points->p[i].assign != i) {
      relweight=points->p[points->p[i].assign].weight + points->p[i].weight;

      relweight = points->p[i].weight/relweight;
      for (ii=0;ii<points->dim;ii++) {
				points->p[points->p[i].assign].coord[ii]*=1.0-relweight;
				points->p[points->p[i].assign].coord[ii]+=
				points->p[i].coord[ii]*relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }

  return 0;
}

void copycenters(Points *points, Points* centers, long* centerIDs, long offset)
{
  long i;
  long k;

  bool *is_a_median = (bool *) calloc(points->num, sizeof(bool));

  for ( i = 0; i < points->num; i++ ) {
    is_a_median[points->p[i].assign] = 1;
  }

  k=centers->num;

  for ( i = 0; i < points->num; i++ ) {
    if ( is_a_median[i] ) {
      memcpy( centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;
  free(is_a_median);
}

void* localSearchSub(void* arg_) {
  pkmedian_arg_t* arg= (pkmedian_arg_t*)arg_;
  pkmedian(arg->points,arg->kmin,arg->kmax,arg->kfinal,arg->pid,arg->barrier);

  return NULL;
}

void localSearch( Points* points, long kmin, long kmax, long* kfinal ) {
  pthread_barrier_t barrier;
  pthread_barrier_init(&barrier,NULL,nproc);
  pthread_t* threads = new pthread_t[nproc];
  pkmedian_arg_t* arg = new pkmedian_arg_t[nproc];

  for( int i = 0; i < nproc; i++ ) {
    arg[i].points = points;
    arg[i].kmin = kmin;
    arg[i].kmax = kmax;
    arg[i].pid = i;
    arg[i].kfinal = kfinal;

    arg[i].barrier = &barrier;
    pthread_create(threads+i,NULL,localSearchSub,(void*)&arg[i]);
  }

  for ( int i = 0; i < nproc; i++) {
    pthread_join(threads[i],NULL);
  }

  delete[] threads;
  delete[] arg;
  pthread_barrier_destroy(&barrier);
}

void outcenterIDs( Points* centers, long* centerIDs, char* outfile ) {
  FILE* fp = fopen(outfile, "w");
  if( fp==NULL ) {
    fprintf(stderr, "error opening %s\n",outfile);
    exit(1);
  }
  int* is_a_median = (int*)calloc( sizeof(int), centers->num );
  for( int i =0 ; i< centers->num; i++ ) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for( int i = 0; i < centers->num; i++ ) {
    if( is_a_median[i] ) {
      fprintf(fp, "%ld\n", centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for( int k = 0; k < centers->dim; k++ ) {
	fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp,"\n\n");
    }
  }
  fclose(fp);
}

class PStream {
public:
  virtual size_t read( float* dest, int dim, int num ) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {
  }
};

class SimStream : public PStream {
public:
  SimStream(long n_ ) {
    n = n_;
  }
  size_t read( float* dest, int dim, int num ) {
    size_t count = 0;
    for( int i = 0; i < num && n > 0; i++ ) {
      for( int k = 0; k < dim; k++ ) {
	dest[i*dim + k] = lrand48()/(float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() {
    return 0;
  }
  int feof() {
    return n <= 0;
  }
private:
  long n;
};

class FileStream : public PStream {
public:
  FileStream(char* filename) {
    fp = fopen( filename, "rb");
    if( fp == NULL ) {
      fprintf(stderr,"error opening file %s\n.",filename);
      exit(1);
    }
  }
  size_t read( float* dest, int dim, int num ) {
    return std::fread(dest, sizeof(float)*dim, num, fp);
  }
  int ferror() {
    return std::ferror(fp);
  }
  int feof() {
    return std::feof(fp);
  }
  ~FileStream() {
    fclose(fp);
  }
private:
  FILE* fp;
};

void streamCluster( PStream* stream,
		    long kmin, long kmax, int dim,
		    long chunksize, long centersize, char* outfile )
{

  float* block = (float*)malloc( chunksize*dim*sizeof(float) );
  float* centerBlock = (float*)malloc(centersize*dim*sizeof(float) );
  long* centerIDs = (long*)malloc(centersize*dim*sizeof(long));

  if( block == NULL ) {
    fprintf(stderr,"not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc(chunksize*sizeof(Point));
  for( int i = 0; i < chunksize; i++ ) {
    points.p[i].coord = &block[i*dim];
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc(centersize*sizeof(Point));
  centers.num = 0;

  for( int i = 0; i< centersize; i++ ) {
    centers.p[i].coord = &centerBlock[i*dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while(1) {

    size_t numRead  = stream->read(block, dim, chunksize );
    fprintf(stderr,"read %lu points\n",numRead);

    if( stream->ferror() || numRead < (unsigned int)chunksize && !stream->feof() ) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = numRead;
    for( int i = 0; i < points.num; i++ ) {
      points.p[i].weight = 1.0;
    }

    switch_membership = (char*)malloc(points.num*sizeof(char));
    is_center = (bool*)calloc(points.num,sizeof(bool));
    center_table = (int*)malloc(points.num*sizeof(int));

    localSearch(&points,kmin, kmax,&kfinal);

    fprintf(stderr,"finish local search\n");
    contcenters(&points);
    if( kfinal + centers.num > centersize ) {

      fprintf(stderr,"oops! no more space for centers\n");
      exit(1);
    }

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += numRead;

    free(is_center);
    free(switch_membership);
    free(center_table);
    if( stream->feof() ) {
      break;
    }
  }

  switch_membership = (char*)malloc(centers.num*sizeof(char));
  is_center = (bool*)calloc(centers.num,sizeof(bool));
  center_table = (int*)malloc(centers.num*sizeof(int));

  localSearch( &centers, kmin, kmax ,&kfinal );
  contcenters(&centers);
  outcenterIDs( &centers, centerIDs, outfile);

  free(block);
  free(centerBlock);
  free(centerIDs);
  free(points.p);
  free(centers.p);
}

int main(int argc, char **argv)
{
  char outfilename[1024];
  char infilename[1024];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;

  if (argc<11) {
    fprintf(stderr,"usage: %s k1 k2 d n chunksize clustersize infile outfile nproc [-p platform] [-d device]\n",
	    argv[0]);
    fprintf(stderr,"  k1:          Min. number of centers allowed\n");
    fprintf(stderr,"  k2:          Max. number of centers allowed\n");
    fprintf(stderr,"  d:           Dimension of each data point\n");
    fprintf(stderr,"  n:           Number of data points\n");
    fprintf(stderr,"  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr,"  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr,"  infile:      Input file (if n<=0)\n");
    fprintf(stderr,"  outfile:     Output file\n");
    fprintf(stderr,"  nproc:       Number of threads to use\n");
    fprintf(stderr,"  platform:    Platform id\n");
    fprintf(stderr,"  device:      Device id\n");
    fprintf(stderr,"\n");
    fprintf(stderr, "if n > 0, points will be randomly generated instead of reading from infile.\n");
    exit(1);
  }
  kmin = atol(argv[1]);
  kmax = atol(argv[2]);
  dim = atoi(argv[3]);
  n = atol(argv[4]);
  chunksize = atol(argv[5]);
  clustersize = atol(argv[6]);
  strncpy(infilename, argv[7], 1023);
  infilename[1023] = '\0';
  strncpy(outfilename, argv[8], 1023);
  outfilename[1023] = '\0';
  nproc = atoi(argv[9]);

  srand48(1);

  PStream* stream;
  if( n > 0 ) {
    stream = new SimStream(n);
  }
  else {
    stream = new FileStream(infilename);
  }

  fprintf(stderr, "Total: %ld\n", n);
  fprintf(stderr, "loops=%d\n", nproc);

  streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename );

  delete stream;

  return 0;
}
